# Check whether a vector is a valid mixed strategy
is_mixed_strategy <- function(p, tol = 1e-10) {
  all(p >= -tol) && abs(sum(p) - 1) < tol
}

is_mixed_strategy(c(0.3, 0.5, 0.2))#> [1] TRUE
is_mixed_strategy(c(0.5, 0.6, -0.1))#> [1] FALSE

